const input = $input.first().json;
const body = input.body || input;
const event = body.event || body.type || body.eventType || '';
const inbound = body.whatsappInboundMessage || body.inboundMessage || body.message || body.data?.message || body.data || body;
const contact = body.contact || body.customer || inbound.contact || inbound.customer || {};
const profile = inbound.profile || contact.profile || {};
const textValue = inbound.text?.body || inbound.text || inbound.body || inbound.content || body.text?.body || body.text || '';
const fromValue = inbound.from || body.from || contact.phone || contact.phoneNumber || contact.waId || contact.wa_id || inbound.sender?.phone || '';
const nameValue = profile.name || contact.name || contact.fullName || inbound.sender?.name || 'Cliente WhatsApp';
const messageType = inbound.type || body.messageType || body.message_type || 'text';
const attachments = [];
const captions = [];
for (const key of ['image', 'document', 'audio', 'video', 'sticker']) {
  const media = inbound[key] || body[key];
  if (!media) continue;
  if (media.caption) captions.push(media.caption);
  if (media.url || media.link || media.id) {
    attachments.push({
      type: key,
      url: media.url || media.link,
      link: media.link,
      id: media.id,
      mime_type: media.mime_type || media.mimeType,
      file_name: media.file_name || media.filename || media.name
    });
  }
}
if (Array.isArray(inbound.attachments)) attachments.push(...inbound.attachments);
const proofText = [String(textValue || ''), ...captions].filter(Boolean).join('\n');

return [{
  json: {
    provider: 'ycloud',
    event,
    phone: String(fromValue).replace(/\D/g, ''),
    from: String(fromValue).replace(/\D/g, ''),
    customerName: nameValue,
    name: nameValue,
    text: String(textValue || ''),
    messageText: String(textValue || ''),
    proofText,
    message: {
      id: inbound.id || body.id || body.messageId,
      type: messageType,
      body: String(textValue || ''),
      text: String(textValue || ''),
      from: String(fromValue).replace(/\D/g, ''),
      fromMe: Boolean(inbound.fromMe || inbound.from_me || body.fromMe),
      attachments
    },
    contact: {
      name: nameValue,
      phone: String(fromValue).replace(/\D/g, ''),
      phone_number: String(fromValue).replace(/\D/g, '')
    },
    ycloud: body
  }
}];

const bot = $input.first().json;
const normalized = $('Normalize YCloud Event').first().json;
const rawPhone = String(bot.replyTargetPhone || bot.phone || '').replace(/\D/g, '');
const inboundTo = String(normalized.ycloud?.whatsappInboundMessage?.to || normalized.ycloud?.to || '').trim();
const fromPhone = String($env.YCLOUD_WHATSAPP_FROM || inboundTo || '+59178096231').trim();
const toPhone = rawPhone ? (rawPhone.startsWith('+') ? rawPhone : `+${rawPhone}`) : '';
const textMessages = Array.isArray(bot.replyMessages)
  ? bot.replyMessages.map((message) => String(message || '').trim()).filter(Boolean)
  : String(bot.replyText || '').split(/\n{2,}/).map((message) => message.trim()).filter(Boolean);
const qrUrl = bot.payment_flow?.qrUrl || bot.paymentFlow?.qrUrl || bot.paymentQrUrl || '';

if (!fromPhone || !toPhone || (!textMessages.length && !qrUrl)) {
  return [{ json: { bot, shouldSend: false, reason: !fromPhone ? 'missing from' : !toPhone ? 'missing phone' : 'empty reply' } }];
}

const outbound = textMessages.map((message) => ({
  type: 'text',
  ycloudRequest: {
    from: fromPhone,
    to: toPhone,
    type: 'text',
    text: { body: message }
  }
}));

if (qrUrl) {
  outbound.push({
    type: 'image',
    ycloudRequest: {
      from: fromPhone,
      to: toPhone,
      type: 'image',
      image: {
        link: qrUrl,
        caption: 'QR de pago Nachito Store'
      }
    }
  });
}

return outbound.map((message, index) => ({
  json: {
    bot,
    shouldSend: true,
    index,
    outboundType: message.type,
    ycloudRequest: message.ycloudRequest
  }
}));

const enriched = $('Attach AI Intent').first().json;
const ai = $input.first().json || {};
const proofEvidence = ai.proofEvidence || {};
const proofText = ai.proofText || enriched.proofText || '';
return [{
  json: {
    ...enriched,
    proofText,
    ocrText: proofText,
    proofEvidence,
    proofAi: {
      available: Boolean(ai.aiAvailable),
      reason: ai.aiReason || ai.reason || null
    }
  }
}];

