const normalized = $('Normalize YCloud Event').first().json;
const agent = $input.first().json || {};
const raw = String(agent.output || agent.text || agent.response || agent.message?.content || '').trim();
let parsed = null;
const jsonStart = raw.indexOf('{');
const jsonEnd = raw.lastIndexOf('}');
const jsonText = jsonStart >= 0 && jsonEnd > jsonStart ? raw.slice(jsonStart, jsonEnd + 1) : raw;
try {
  parsed = JSON.parse(jsonText);
} catch (error) {
  parsed = null;
}
const allowed = new Set(['greeting','unknown','confirm','cancel','change','fresh_order','human','half_payment','full_payment','payment_proof','faq']);
const confidence = Number(parsed?.confidence || 0);
const hasAttachment = Array.isArray(normalized.message?.attachments) && normalized.message.attachments.length > 0;
const intent = allowed.has(parsed?.intent) ? parsed.intent : 'unknown';
const safeIntent = intent === 'payment_proof' && !hasAttachment ? 'unknown' : intent;
const aiIntent = {
  intent: safeIntent,
  confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0,
  safeToUse: parsed?.safeToUse !== false,
  reason: String(parsed?.reason || raw || '').slice(0, 500),
  paymentChoice: parsed?.paymentChoice === '50%' || parsed?.paymentChoice === 'completo' ? parsed.paymentChoice : null,
  deliveryZone: parsed?.deliveryZone === 'santa_cruz' || parsed?.deliveryZone === 'otro_departamento' ? parsed.deliveryZone : null,
  department: parsed?.department ? String(parsed.department).slice(0, 80) : null,
  normalizedText: parsed?.normalizedText ? String(parsed.normalizedText).slice(0, 500) : ''
};
return [{ json: { ...normalized, aiIntent } }];

const bot = $('Run Bot in PoleraFlow').first().json;
const agent = $input.first().json || {};
const raw = String(agent.output || agent.text || agent.response || agent.message?.content || '').trim();
const originalMessages = Array.isArray(bot.replyMessages)
  ? bot.replyMessages.map((message) => String(message || '').trim()).filter(Boolean)
  : String(bot.replyText || '').split(/\n{2,}/).map((message) => message.trim()).filter(Boolean);

let parsed = null;
const jsonStart = raw.indexOf('{');
const jsonEnd = raw.lastIndexOf('}');
const jsonText = jsonStart >= 0 && jsonEnd > jsonStart ? raw.slice(jsonStart, jsonEnd + 1) : raw;
try {
  parsed = JSON.parse(jsonText);
} catch (error) {
  parsed = null;
}

function cleanMessage(value) {
  return String(value || '')
    .replace(/\r/g, '')
    .replace(/\n{4,}/g, '\n\n')
    .trim()
    .slice(0, 900);
}

const hasQr = Boolean(bot.payment_flow?.qrUrl || bot.paymentFlow?.qrUrl || bot.paymentQrUrl);
const proposed = Array.isArray(parsed?.replyMessages)
  ? parsed.replyMessages.map(cleanMessage).filter(Boolean).slice(0, 3)
  : [];
const originalText = originalMessages.join('\n\n');
const proposedText = proposed.join('\n\n');

const originalAmounts = [...originalText.matchAll(/\b\d+(?:[.,]\d+)?\s*Bs\b/gi)].map((match) => match[0]);
const preservesAmounts = originalAmounts.every((amount) => proposedText.includes(amount));
const safe = parsed?.safeToUse !== false && proposed.length > 0 && proposedText.length <= 1800 && (!originalAmounts.length || preservesAmounts);

if (!bot.replyText || !originalMessages.length || !safe) {
  return [{ json: { ...bot, aiHumanReply: { used: false, reason: parsed?.reason || raw || 'fallback_original' } } }];
}

return [{
  json: {
    ...bot,
    replyText: proposedText,
    replyMessages: proposed,
    aiHumanReply: {
      used: true,
      reason: parsed?.reason || 'humanized',
      hasQr
    }
  }
}];
